+                continue
+            if (!sPrefs.getString(area.value.area + "_server", null).isNullOrBlank() &&
+                sPrefs.getBoolean("search_area_" + area.value.type_str, false)
+            ) {
+                val nav = searchNav {
+                    name = area.value.text
+                    total = 0
+                    pages = 0
+                    type = area.key
+                }
+                navList.add(1, nav)
